import { publicApi } from "shared/api/Api";
import { API_ROUTES } from "shared/api/ApiRoutes";

export const FetchProducs = async () => {
  try {
      const response = await publicApi.get(API_ROUTES.products.list);
      return response.data;
  } catch (error) {
    return null;
  }
};

import React, { useEffect, useMemo } from 'react';
import {
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Typography,
  IconButton,
  Chip,
  Box,
  Button,
} from '@mui/material';
import DeleteIcon from '@mui/icons-material/Delete';
import AddIcon from '@mui/icons-material/Add';
import { useNavigate } from 'react-router-dom';
import { useAppDispatch, useAppSelector } from 'app/store/Store';
import { adminAllCoupons, adminDeleteCoupon } from 'State/backend/MasterApiThunks';

const Coupon = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const responses = useAppSelector((state) => state.masterApi.responses);
  const loading = useAppSelector((state) => state.masterApi.loading);
  const rawCoupons = responses.adminAllCoupons;

  useEffect(() => {
    dispatch(adminAllCoupons());
  }, [dispatch]);

  const coupons = useMemo(() => {
    if (!Array.isArray(rawCoupons)) return [];
    return rawCoupons.map((coupon: any) => ({
      id: coupon.id,
      name: coupon.code || coupon.name || "N/A",
      startDate: coupon.startDate || coupon.validFrom || coupon.createdAt || "",
      endDate: coupon.endDate || coupon.validUntil || "",
      minOrderValue: coupon.minimumOrderValue || coupon.minOrderValue || 0,
      discount: coupon.discountPercentage || coupon.discount || 0,
      status: coupon.active ? "ACTIVE" : coupon.status || "ACTIVE",
    }));
  }, [rawCoupons]);

  const handleDelete = async (id: number) => {
    if (globalThis.confirm("Are you sure you want to delete this coupon?")) {
      await dispatch(adminDeleteCoupon(id));
      await dispatch(adminAllCoupons());
    }
  };

  const isExpired = (endDate: string) => {
    return new Date(endDate) < new Date();
  };

  return (
    <Box>
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
        <Typography variant="h5" sx={{ fontWeight: 'bold', color: 'teal.800' }}>
          Coupon Management
        </Typography>
        <Button 
          variant="contained" 
          startIcon={<AddIcon />}
          onClick={() => navigate("/admin/add-new-coupon-from")}
          sx={{ bgcolor: 'teal.600', '&:hover': { bgcolor: 'teal.700' }, textTransform: 'none' }}
        >
          Create New Coupon
        </Button>
      </Box>

      <TableContainer component={Paper} elevation={0} sx={{ border: '1px solid #e0e0e0', borderRadius: '12px' }}>
        <Table sx={{ minWidth: 800 }}>
          <TableHead sx={{ bgcolor: '#f8fafc' }}>
            <TableRow>
              <TableCell sx={{ fontWeight: 'bold' }}>Coupon code</TableCell>
              <TableCell sx={{ fontWeight: 'bold' }}>Start Date</TableCell>
              <TableCell sx={{ fontWeight: 'bold' }}>End Date</TableCell>
              <TableCell sx={{ fontWeight: 'bold' }}>Min Order Value</TableCell>
              <TableCell sx={{ fontWeight: 'bold' }}>Discount (%)</TableCell>
              <TableCell sx={{ fontWeight: 'bold' }}>Status</TableCell>
              <TableCell sx={{ fontWeight: 'bold' }} align="right">Actions</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {coupons.map((coupon: any) => {
              const expired = isExpired(coupon.endDate);
              return (
                <TableRow key={coupon.id} hover>
                  <TableCell>
                    <Typography variant="subtitle2" sx={{ color: 'teal.700', fontWeight: 'bold' }}>
                      {coupon.name}
                    </Typography>
                  </TableCell>
                  <TableCell>{coupon.startDate}</TableCell>
                  <TableCell>{coupon.endDate}</TableCell>
                  <TableCell>₹{coupon.minOrderValue}</TableCell>
                  <TableCell>{coupon.discount}%</TableCell>
                  <TableCell>
                    <Chip 
                      label={expired ? "EXPIRED" : coupon.status} 
                      color={expired || coupon.status === 'EXPIRED' ? 'error' : 'success'} 
                      size="small" 
                      variant="outlined"
                    />
                  </TableCell>
                  <TableCell align="right">
                    <IconButton 
                      onClick={() => handleDelete(coupon.id)} 
                      color="error" 
                      size="small"
                      sx={{ '&:hover': { bgcolor: '#fff1f2' } }}
                    >
                      <DeleteIcon />
                    </IconButton>
                  </TableCell>
                </TableRow>
              );
            })}
            {!coupons.length && (
              <TableRow>
                <TableCell colSpan={7} align="center">
                  {loading ? "Loading coupons..." : "No coupons found"}
                </TableCell>
              </TableRow>
            )}
          </TableBody>
        </Table>
      </TableContainer>
    </Box>
  );
};

export default Coupon;

import React, { useEffect } from "react";
import {
  Alert,
  Chip,
  CircularProgress,
  Paper,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Typography,
} from "@mui/material";
import { adminOrdersList } from "State/backend/MasterApiThunks";
import { useAppDispatch, useAppSelector } from "app/store/Store";

const AdminOrders = () => {
  const dispatch = useAppDispatch();
  const { loading, error, responses } = useAppSelector((state) => state.masterApi);
  const orders = Array.isArray(responses.adminOrdersList) ? responses.adminOrdersList : [];

  const getOrderStatusColor = (status?: string) => {
    switch ((status || "").toUpperCase()) {
      case "DELIVERED":
        return "success";
      case "CANCELLED":
        return "error";
      case "SHIPPED":
      case "OUT_FOR_DELIVERY":
      case "CONFIRMED":
        return "info";
      default:
        return "warning";
    }
  };

  const getPaymentStatusColor = (status?: string) => {
    switch ((status || "").toUpperCase()) {
      case "COMPLETED":
      case "SUCCESS":
        return "success";
      case "FAILED":
        return "error";
      case "REFUNDED":
        return "info";
      default:
        return "warning";
    }
  };

  useEffect(() => {
    dispatch(adminOrdersList());
  }, [dispatch]);

  return (
    <div className="space-y-5">
      <div>
        <Typography variant="h5" sx={{ fontWeight: 800 }}>
          Order Monitoring
        </Typography>
        <Typography variant="body2" color="text.secondary">
          Admin overview of placed orders, payment state, and seller ownership.
        </Typography>
      </div>

      {error && <Alert severity="error">{error}</Alert>}

      <TableContainer component={Paper} sx={{ borderRadius: "24px", boxShadow: "none", border: "1px solid #eef2f7" }}>
        <Table>
          <TableHead sx={{ bgcolor: "#f8fafc" }}>
            <TableRow>
              <TableCell sx={{ fontWeight: 700 }}>Order</TableCell>
              <TableCell sx={{ fontWeight: 700 }}>Customer</TableCell>
              <TableCell sx={{ fontWeight: 700 }}>Seller</TableCell>
              <TableCell sx={{ fontWeight: 700 }}>Order Status</TableCell>
              <TableCell sx={{ fontWeight: 700 }}>Payment Status</TableCell>
              <TableCell sx={{ fontWeight: 700 }}>Amount</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {loading && orders.length === 0 ? (
              <TableRow>
                <TableCell colSpan={6} align="center" sx={{ py: 5 }}>
                  <CircularProgress />
                </TableCell>
              </TableRow>
            ) : orders.length === 0 ? (
              <TableRow>
                <TableCell colSpan={6} align="center" sx={{ py: 4 }}>
                  No orders found.
                </TableCell>
              </TableRow>
            ) : (
              orders.map((order: any) => (
                <TableRow key={order.id} hover>
                  <TableCell>
                    <Typography variant="body2" sx={{ fontWeight: 700 }}>
                      #{order.id}
                    </Typography>
                    <Typography variant="caption" color="text.secondary">
                      {order.orderDate ? new Date(order.orderDate).toLocaleString() : "-"}
                    </Typography>
                  </TableCell>
                  <TableCell>
                    <Typography variant="body2" sx={{ fontWeight: 700 }}>
                      {order.customerName || "N/A"}
                    </Typography>
                    <Typography variant="caption" color="text.secondary">
                      {order.customerEmail || "N/A"}
                    </Typography>
                  </TableCell>
                  <TableCell>{order.sellerName || "N/A"}</TableCell>
                  <TableCell>
                    <Chip
                      size="small"
                      label={order.orderStatus || "N/A"}
                      color={getOrderStatusColor(order.orderStatus) as any}
                      variant="outlined"
                    />
                  </TableCell>
                  <TableCell>
                    <Chip
                      size="small"
                      label={order.paymentStatus || "N/A"}
                      color={getPaymentStatusColor(order.paymentStatus) as any}
                    />
                  </TableCell>
                  <TableCell>
                    <Typography variant="body2" sx={{ fontWeight: 700 }}>
                      Rs {order.totalSellingPrice}
                    </Typography>
                    <Typography variant="caption" color="text.secondary">
                      {order.totalItems} items
                    </Typography>
                  </TableCell>
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </TableContainer>
    </div>
  );
};

export default AdminOrders;

