import React, { useEffect, useMemo, useState } from "react";
import { Alert, Button, Divider } from "@mui/material";
import { useAppDispatch, useAppSelector } from "app/store/Store";
import LockIcon from '@mui/icons-material/Lock';
import {
  getUserProfile,
  requestEmailChangeOtp,
  updateUserProfile,
  verifyEmailChangeOtp,
} from "State/features/customer/auth/thunks";
import EmailChangePanel from "../components/EmailChangePanel";
import ProfileEditForm from "../components/ProfileEditForm";
import ProfileSummary from "../components/ProfileSummary";
import { resolveEmailFlowMessage, validateProfileDetails } from "../components/profileHelpers";

type UserDetailsMode = "profile" | "full";

interface UserDetailsProps {
  mode?: UserDetailsMode;
}

const UserDetails = ({ mode = "full" }: UserDetailsProps) => {
  const dispatch = useAppDispatch();
  const { user, loading, error } = useAppSelector((state) => state.customerAuth);
  const [isEditing, setIsEditing] = useState(false);
  const [fullName, setFullName] = useState("");
  const [mobileNumber, setMobileNumber] = useState("");
  const [newEmail, setNewEmail] = useState("");
  const [emailOtp, setEmailOtp] = useState("");
  const [emailOtpSent, setEmailOtpSent] = useState(false);
  const [otpRequestedFor, setOtpRequestedFor] = useState("");
  const [emailFlowMessage, setEmailFlowMessage] = useState<string | null>(null);
  const [showEmailChangeForm, setShowEmailChangeForm] = useState(false);
  const [otpError, setOtpError] = useState<string | null>(null);
  const [profileErrors, setProfileErrors] = useState<{ fullName?: string; mobileNumber?: string }>({});

  const normalizedEmail = newEmail.trim().toLowerCase();
  const currentEmail = (user?.email || "").trim().toLowerCase();
  const isValidEmail = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(normalizedEmail);
  const canSendOtp =
    isValidEmail && normalizedEmail.length > 0 && normalizedEmail !== currentEmail && !loading;
  const canVerifyOtp =
    canSendOtp &&
    emailOtp.trim().length > 0 &&
    emailOtpSent &&
    otpRequestedFor === normalizedEmail &&
    !loading;
  const shouldShowOtpInput = emailOtpSent && otpRequestedFor === normalizedEmail;

  useEffect(() => {
    if (!user) {
      dispatch(getUserProfile());
      return;
    }
    setFullName(user.fullName || "");
    setMobileNumber(user.mobileNumber || "");
  }, [dispatch, user]);

  const handleSave = async () => {
    const errors = validateProfileDetails(fullName, mobileNumber);
    setProfileErrors(errors);
    if (Object.keys(errors).length > 0) {
      return;
    }

    await dispatch(updateUserProfile({ fullName: fullName.trim(), mobileNumber: mobileNumber.trim() })).unwrap();
    setIsEditing(false);
  };

  const handleRequestEmailOtp = async () => {
    setEmailFlowMessage(null);
    setOtpError(null);
    try {
      if (!normalizedEmail) {
        setEmailFlowMessage("Please enter new email.");
        return;
      }
      if (normalizedEmail === currentEmail) {
        setEmailFlowMessage("New email must be different from current email.");
        return;
      }
      await dispatch(requestEmailChangeOtp(normalizedEmail)).unwrap();
      setEmailOtpSent(true);
      setOtpRequestedFor(normalizedEmail);
      setEmailOtp("");
      setEmailFlowMessage("OTP sent to new email.");
    } catch (e: any) {
      const resolved = resolveEmailFlowMessage(e, "Failed to send OTP");
      setEmailFlowMessage(resolved.message);
    }
  };

  const handleVerifyEmailOtp = async () => {
    setEmailFlowMessage(null);
    setOtpError(null);
    try {
      if (!normalizedEmail || !emailOtp.trim()) {
        setEmailFlowMessage("Please enter email and OTP.");
        return;
      }
      if (normalizedEmail === currentEmail) {
        setEmailFlowMessage("New email must be different from current email.");
        return;
      }
      if (otpRequestedFor !== normalizedEmail) {
        setEmailFlowMessage("Email input changed. Request OTP again for this email.");
        return;
      }
      await dispatch(verifyEmailChangeOtp({ newEmail: normalizedEmail, otp: emailOtp.trim() })).unwrap();
      await dispatch(getUserProfile()).unwrap();
      setEmailFlowMessage("Email updated successfully. You are still logged in.");
      setEmailOtp("");
      setEmailOtpSent(false);
      setOtpRequestedFor("");
      setShowEmailChangeForm(false);
      setNewEmail("");
    } catch (e: any) {
      const resolved = resolveEmailFlowMessage(e, "OTP verification failed");
      if (resolved.type === "otp") {
        setOtpError(resolved.message);
      } else {
        setEmailFlowMessage(resolved.message);
      }
    }
  };

  const handleEmailInputChange = (value: string) => {
    const nextEmail = value.trim().toLowerCase();
    setNewEmail(value);

    if (otpRequestedFor && otpRequestedFor !== nextEmail) {
      setEmailOtpSent(false);
      setEmailOtp("");
      setOtpError(null);
      setEmailFlowMessage("Email changed. Request OTP again for the new email.");
    }
  };
  const location = useMemo(
    () =>
      user?.addresses?.[0]
        ? `${user.addresses[0].city}, ${user.addresses[0].state}`
        : "Not Set",
    [user?.addresses],
  );

  const emailChangePanel = (
    <EmailChangePanel
      loading={loading}
      newEmail={newEmail}
      emailOtp={emailOtp}
      isValidEmail={isValidEmail}
      canSendOtp={canSendOtp}
      canVerifyOtp={canVerifyOtp}
      shouldShowOtpInput={shouldShowOtpInput}
      otpRequestedFor={otpRequestedFor}
      emailFlowMessage={emailFlowMessage}
      otpError={otpError}
      onEmailChange={handleEmailInputChange}
      onOtpChange={(value) => {
        setEmailOtp(value);
        if (otpError) setOtpError(null);
      }}
      onRequestOtp={handleRequestEmailOtp}
      onVerifyOtp={handleVerifyEmailOtp}
    />
  );

  if (!user) return <Alert severity="info">Loading profile...</Alert>;

  return (
    <div className="space-y-8">
      <h1 className="text-xl sm:text-2xl font-bold text-[#282c3f]">Profile Details</h1>

      {error && <Alert severity="error">{error}</Alert>}

      <div className="border border-gray-300 p-4 sm:p-7" id="profile">
        <h2 className="text-lg font-semibold text-[#282c3f] mb-4 sm:mb-6">
          {isEditing ? "Edit Details" : "Profile Details"}
        </h2>
        <Divider sx={{ mb: 3 }} />
        {!isEditing ? (
          <ProfileSummary
            fullName={user.fullName}
            mobileNumber={user.mobileNumber}
            email={user.email}
            location={location}
            onEdit={() => setIsEditing(true)}
          />
        ) : (
          <ProfileEditForm
            fullName={fullName}
            mobileNumber={mobileNumber}
            loading={loading}
            fullNameError={profileErrors.fullName}
            mobileNumberError={profileErrors.mobileNumber}
            showEmailChangeForm={showEmailChangeForm}
            emailPanel={emailChangePanel}
            onFullNameChange={(value) => {
              setFullName(value);
              if (profileErrors.fullName) {
                setProfileErrors((prev) => ({ ...prev, fullName: undefined }));
              }
            }}
            onMobileNumberChange={(value) => {
              setMobileNumber(value);
              if (profileErrors.mobileNumber) {
                setProfileErrors((prev) => ({ ...prev, mobileNumber: undefined }));
              }
            }}
            onCancel={() => {
              setIsEditing(false);
              setProfileErrors({});
              setFullName(user.fullName || "");
              setMobileNumber(user.mobileNumber || "");
            }}
            onSave={handleSave}
          />
        )}
      </div>

      {/* Login Security Section */}
      {mode === "full" && !isEditing && (
      <section className="pt-2 border-t border-gray-200">
        <h2 className="text-lg sm:text-xl font-bold mb-4 sm:mb-6 flex items-center gap-2">
          <LockIcon className="text-blue-600" />Login & Security
        </h2>

        <div className="bg-gray-50 p-4 sm:p-6 rounded-2xl border border-gray-100">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-4 sm:mb-6 gap-2">
            <div>
              <p className="font-semibold text-gray-700 text-sm sm:text-base">Primary Email</p>
              <p className="text-gray-500 text-sm break-all">{user.email}</p>
            </div>
            <span className="mt-1 md:mt-0 px-2.5 py-1 bg-green-100 text-green-700 text-[10px] sm:text-xs font-bold rounded-full uppercase">Verified</span>
          </div>

          {!showEmailChangeForm ? (
            <Button
              variant="outlined"
              size="small"
              color="primary"
              onClick={() => setShowEmailChangeForm(true)}
              sx={{ fontWeight: 700, fontSize: "0.75rem", px: 1.5, py: 0.75 }}
            >
              Change Email Address?
            </Button>
          ) : (
            <div className="animate-in fade-in slide-in-from-top-2">
              <Divider sx={{ my: 2 }} />
              {emailChangePanel}
              <Button
                size="small"
                color="inherit"
                onClick={() => setShowEmailChangeForm(false)}
                sx={{ mt: 1.5, fontSize: "0.72rem" }}
              >
                Cancel Change
              </Button>
            </div>
          )}
        </div>
      </section>
      )}

    </div>
  );
};

export default UserDetails;

import React, { useEffect } from "react";
import { Alert, Button, CircularProgress } from "@mui/material";
import FavoriteIcon from "@mui/icons-material/Favorite";
import DeleteOutlineIcon from "@mui/icons-material/DeleteOutline";
import AddShoppingCartIcon from "@mui/icons-material/AddShoppingCart";
import { useNavigate } from "react-router-dom";
import { useAppDispatch, useAppSelector } from "app/store/Store";
import {
  fetchWishlist,
  removeWishlistProduct,
} from "State/features/customer/wishlist/slice";
import { addToCart } from "State/features/customer/cart/slice";

type WishlistItem = {
  id?: number;
  title?: string;
  categoryId?: string;
  categoryName?: string;
  sellingPrice?: number;
  mrpPrice?: number;
  sizes?: string | string[];
  images?: string[];
  category?: {
    name?: string;
    categoryId?: string;
  };
};

const Wishlist = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const customer = useAppSelector((state) => state.customerAuth.user);
  const { items, loading, actionLoading, error } = useAppSelector(
    (state) => state.wishlist,
  );
  const typedItems = items as WishlistItem[];

  useEffect(() => {
    if (!customer) return;
    dispatch(fetchWishlist());
  }, [customer, dispatch]);

  const getDefaultSize = (sizes: unknown): string => {
    if (Array.isArray(sizes) && sizes.length > 0) {
      return String(sizes[0]);
    }
    if (typeof sizes === "string" && sizes.trim().length > 0) {
      const first = sizes.split(",")[0]?.trim();
      return first || "M";
    }
    return "M";
  };

  const handleRemove = async (productId?: number) => {
    if (!productId) return;
    await dispatch(removeWishlistProduct(productId));
  };

  const handleOpenProductDetails = (item: WishlistItem) => {
    if (!item?.id) return;
    const categoryId = item?.categoryId || item?.category?.categoryId || "all";
    const name = item?.title || "product";
    navigate(`/product-details/${categoryId}/${name}/${item.id}`);
  };

  const handleAddToCart = async (e: React.MouseEvent, item: WishlistItem) => {
    e.stopPropagation();
    if (!item?.id) return;
    try {
      await dispatch(
        addToCart({
          productId: item.id,
          quantity: 1,
          size: getDefaultSize(item.sizes),
        }),
      ).unwrap();
    } catch (e) {
      // Keep UX simple for now and use existing app alert pattern.
      alert("Failed to add product to cart.");
    }
  };

  if (loading) {
    return (
      <div className="w-full py-12 flex justify-center">
        <CircularProgress />
      </div>
    );
  }

  return (
    <div className="w-full space-y-4 sm:space-y-5">
      <div className="flex items-center gap-2">
        <FavoriteIcon className="text-red-500" />
        <h1 className="text-xl font-bold">Wishlist</h1>
      </div>

      {error && <Alert severity="error">{error}</Alert>}

      {!typedItems.length ? (
        <div className="border rounded-lg p-5 sm:p-8 text-center">
          <p className="text-gray-600 font-medium">Your wishlist is empty.</p>
          <p className="text-sm text-gray-500 mt-1">
            Products you like will appear here.
          </p>
          <Button
            sx={{ mt: 2, textTransform: "none" }}
            variant="contained"
            onClick={() => navigate("/")}
          >
            Continue Shopping
          </Button>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-3 sm:gap-4">
          {typedItems.map((item) => (
            <div
              key={item.id ?? `${item?.title || "wishlist"}-${item?.categoryId || "all"}`}
              className="border rounded-xl p-3 sm:p-4 bg-white flex flex-col sm:flex-row gap-3 sm:gap-4 items-start cursor-pointer hover:shadow-sm transition"
              onClick={() => handleOpenProductDetails(item)}
            >
              <img
                src={item?.images?.[0] || "/no-image.png"}
                alt={item?.title || "Product"}
                className="w-full sm:w-24 h-40 sm:h-24 rounded-lg object-cover border"
              />
              <div className="flex-1 min-w-0">
                <h2 className="font-semibold text-gray-900 truncate">
                  {item?.title || "Untitled Product"}
                </h2>
                <p className="text-sm text-gray-500 truncate">
                  {item?.categoryName || item?.categoryId || item?.category?.name || item?.category?.categoryId || ""}
                </p>
                <div className="flex items-center gap-2 mt-2">
                  <span className="font-bold">Rs {item?.sellingPrice ?? 0}</span>
                  <span className="line-through text-xs text-gray-400">
                    Rs {item?.mrpPrice ?? 0}
                  </span>
                </div>
                <div className="flex flex-wrap gap-2 mt-3">
                  <Button
                    size="small"
                    variant="contained"
                    startIcon={<AddShoppingCartIcon />}
                    onClick={(e) => handleAddToCart(e, item)}
                    sx={{ textTransform: "none" }}
                  >
                    Add to Cart
                  </Button>
                  <Button
                    size="small"
                    variant="outlined"
                    color="error"
                    startIcon={<DeleteOutlineIcon />}
                    disabled={actionLoading}
                    onClick={(e) => {
                      e.stopPropagation();
                      handleRemove(item.id);
                    }}
                    sx={{ textTransform: "none" }}
                  >
                    Remove
                  </Button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default Wishlist;

