import React, { useEffect, useState } from "react";
import { Button } from "@mui/material";
import FavoriteBorderIcon from "@mui/icons-material/FavoriteBorder";
import FavoriteIcon from "@mui/icons-material/Favorite";
import AddShoppingCartIcon from "@mui/icons-material/AddShoppingCart";
import FlashOnIcon from "@mui/icons-material/FlashOn";
import { useNavigate } from "react-router-dom";
import { Product } from "shared/types/product.types";
import { useAppDispatch, useAppSelector } from "app/store/Store";
import { addToCart } from "State/features/customer/cart/slice";
import { toggleWishlistProduct } from "State/features/customer/wishlist/slice";

const ProductCard = ({ item }: { item: Product }) => {
  const [currentImage, setCurrentImage] = useState(0);
  const [isHovered, setIsHovered] = useState(false);
  const navigate = useNavigate();
  const dispatch = useAppDispatch();
  const customer = useAppSelector((state) => state.customerAuth.user);
  const wishlistItems = useAppSelector((state) => state.wishlist.items);

  const images = item.images || [];
  const isWishlisted = Boolean(
    item.id &&
      wishlistItems.some(
        (wishlistItem: { id?: number } | null | undefined) =>
          wishlistItem?.id === item.id,
      ),
  );

  useEffect(() => {
    let interval: ReturnType<typeof setInterval> | undefined;

    if (isHovered && images.length > 1) {
      interval = setInterval(() => {
        setCurrentImage((prev) => (prev + 1) % images.length);
      }, 1000);
    } else {
      setCurrentImage(0);
    }

    return () => {
      if (interval) clearInterval(interval);
    };
  }, [isHovered, images.length]);

  const getDefaultSize = () => {
    const rawSize = (item as any).size || (item as any).sizes;
    if (typeof rawSize === "string" && rawSize.trim().length > 0) {
      return rawSize.split(",")[0].trim();
    }
    return "M";
  };

  const handleNavigate = () => {
    navigate(`/product-details/${item.category?.categoryId}/${item.title}/${item.id}`);
  };

  const handleToggleWishlist = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!customer) {
      navigate("/login");
      return;
    }
    if (!item.id) return;
    await dispatch(toggleWishlistProduct(item.id));
  };

  const handleAddToCart = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!customer) {
      navigate("/login");
      return;
    }
    if (!item.id) return;
    await dispatch(
      addToCart({
        productId: item.id,
        quantity: 1,
        size: getDefaultSize(),
      }),
    );
  };

  const handleBuyNow = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!customer) {
      navigate("/login");
      return;
    }
    if (!item.id) return;
    await dispatch(
      addToCart({
        productId: item.id,
        quantity: 1,
        size: getDefaultSize(),
      }),
    );
    navigate("/checkout/cart");
  };

  const colorValue = item.color as unknown;
  const displayColor =
    typeof colorValue === "string"
      ? colorValue
      : colorValue &&
          typeof colorValue === "object" &&
          "name" in colorValue &&
          typeof (colorValue as { name?: unknown }).name === "string"
        ? ((colorValue as { name?: string }).name || "N/A")
        : "N/A";
  const fallbackImage =
    "https://images.unsplash.com/photo-1523275335684-37898b6baf30?q=80&w=600&auto=format&fit=crop";

  return (
    <div
      onMouseEnter={() => setIsHovered(true)}
