import { useEffect, useMemo, useState } from "react";
import { deriveCheckoutPricing } from "../utils/pricing";

interface Params {
  cart?: any;
  currentSummary?: any;
}

export const useCheckoutPricing = ({ cart, currentSummary }: Params) => {
  const cartItems = useMemo(() => cart?.cartItems || [], [cart?.cartItems]);
  const [selectedItemIds, setSelectedItemIds] = useState<number[]>([]);

  const featuredCategoryId = useMemo(
    () => cartItems[0]?.product?.category?.categoryId,
    [cartItems],
  );

  const pricing = useMemo(
    () =>
      deriveCheckoutPricing({
        cart,
        currentSummary,
        cartItems,
        selectedItemIds,
      }),
    [cart, cartItems, currentSummary, selectedItemIds],
  );

  useEffect(() => {
    const ids = cartItems.map((item: any) => item?.id).filter(Boolean) as number[];
    setSelectedItemIds((prev) => {
      if (!prev.length) return ids;
      const next = prev.filter((id) => ids.includes(id));
      return next.length ? next : ids;
    });
  }, [cartItems]);

  const allSelected = cartItems.length > 0 && selectedItemIds.length === cartItems.length;

  const toggleSelectAll = () => {
    if (allSelected) {
      setSelectedItemIds([]);
      return;
    }
    const ids = cartItems.map((item: any) => item?.id).filter(Boolean) as number[];
    setSelectedItemIds(ids);
  };

  const toggleSelectItem = (id: number) => {
    setSelectedItemIds((prev) =>
      prev.includes(id) ? prev.filter((itemId) => itemId !== id) : [...prev, id],
    );
  };

  return {
    allSelected,
    cartItems,
    featuredCategoryId,
    pricing,
    selectedItemIds,
    toggleSelectAll,
    toggleSelectItem,
  };
};

import { act, renderHook } from "@testing-library/react";
import { useCheckoutSubmit } from "./useCheckoutSubmit";

const createParams = (overrides?: Partial<any>) => ({
  cart: undefined,
  cartItems: [],
  dispatch: jest.fn(),
  goToStep: jest.fn(),
  handleSelectSavedAddress: jest.fn(),
  navigate: jest.fn(),
  pricing: { selectedPriceSelling: 0 },
  useManualAddress: false,
  setUseManualAddress: jest.fn(),
  addressForm: {
    name: "",
    mobileNumber: "",
    address: "",
    locality: "",
    street: "",
    city: "",
    state: "",
    pinCode: "",
  },
  validateAddress: jest.fn(() => null),
  ...overrides,
});

describe("useCheckoutSubmit", () => {
  test("sets error when placing order with empty cart", async () => {
    const params = createParams();
    const { result } = renderHook(() => useCheckoutSubmit(params));

    await act(async () => {
      await result.current.handlePlaceOrder();
    });

    expect(result.current.submitError).toBe("Your cart is empty.");
    expect(params.goToStep).not.toHaveBeenCalled();
  });

  test("redirects to ADDRESS step when address validation fails", async () => {
    const params = createParams({
      cart: { cartItems: [{ id: 1 }] },
      cartItems: [{ id: 1 }],
      validateAddress: jest.fn(() => "Address is required"),
    });
    const { result } = renderHook(() => useCheckoutSubmit(params));

    await act(async () => {
      await result.current.handlePlaceOrder();
    });

    expect(params.goToStep).toHaveBeenCalledWith("ADDRESS");
    expect(result.current.submitError).toBe("Address is required");
  });
});

export interface CheckoutPricingResult {
  totalMrp: number;
  totalSelling: number;
  discount: number;
  itemCount: number;
  selectedItemCount: number;
  selectedPriceMrp: number;
  selectedPriceSelling: number;
  selectedDiscount: number;
}

export const deriveCheckoutPricing = ({
  cart,
  currentSummary,
  cartItems,
  selectedItemIds,
}: {
  cart?: any;
  currentSummary?: any;
  cartItems: any[];
  selectedItemIds: number[];
}): CheckoutPricingResult => {
  const selectedItems = cartItems.filter((item: any) => selectedItemIds.includes(item.id));
  const selectedMrp = selectedItems.reduce(
    (sum: number, item: any) => sum + (item?.mrpPrice ?? 0),
    0,
  );
  const selectedSelling = selectedItems.reduce(
    (sum: number, item: any) => sum + (item?.sellingPrice ?? 0),
    0,
  );

  const totalMrp = currentSummary?.priceBreakdown?.totalMRP ?? cart?.totalMrpPrice ?? 0;
  const totalSelling =
    currentSummary?.priceBreakdown?.totalSellingPrice ?? cart?.totalSellingPrice ?? 0;
  const discount = currentSummary?.priceBreakdown?.totalDiscount ?? totalMrp - totalSelling;
  const itemCount = currentSummary?.orderItems?.length ?? cartItems.length ?? 0;
  const selectedItemCount = selectedItemIds.length || itemCount;
  const selectedPriceMrp = selectedItemIds.length ? selectedMrp : totalMrp;
  const selectedPriceSelling = selectedItemIds.length ? selectedSelling : totalSelling;
  const selectedDiscount = selectedItemIds.length ? selectedMrp - selectedSelling : discount;

  return {
    totalMrp,
    totalSelling,
    discount,
    itemCount,
    selectedItemCount,
    selectedPriceMrp,
    selectedPriceSelling,
    selectedDiscount,
  };
};

