          <div key={lvl2.categoryId} className="w-[20%] min-w-[200px] mb-10">
            <p className="text-teal-600 mb-4 font-bold text-sm uppercase tracking-widest">
              {lvl2.name}
            </p>
            <ul className="space-y-2.5">
              {getChildCategories(lvl2.categoryId).map((lvl3) => (
