import { useEffect, useMemo, useRef, useState } from "react";
import { Alert, Button, CircularProgress, Stack } from "@mui/material";
import { useLocation, useNavigate, useParams } from "react-router-dom";
import ReturnRefundForm from "./components/ReturnRefundForm";
import ExchangeRequestForm from "./components/ExchangeRequestForm";
import BalanceSelectionForm from "./components/BalanceSelectionForm";
import BankDetailsForm from "./components/BankDetailsForm";
import OrderDetailsDialogs from "./components/orderDetails/OrderDetailsDialogs";
import OrderDetailsHeaderSection from "./components/orderDetails/OrderDetailsHeaderSection";
import OrderDetailsJourneySection from "./components/orderDetails/OrderDetailsJourneySection";
import OrderDetailsProductInfo from "./components/orderDetails/OrderDetailsProductInfo";
import { createOrderDetailsHandlers } from "./orderDetailsHandlers";
import { cancelAllowed, CancelReasonOption, OrderItemLite, OrderLite, resolveCustomerStatus } from "./orderDetailsTypes";
import { orderById, orderCancelReasons, orderItemById, userOrderHistory } from "State/backend/MasterApiThunks";
import { clearExchangeError, clearExchangeSuccess, fetchExchangeRequests, hasActiveExchange, selectLatestExchangeForItem } from "State/features/customer/exchange/slice";
import { useAppDispatch, useAppSelector } from "app/store/Store";
import { buildTrackingMilestones } from "features/courier/courierData";

const OrderDetails = () => {
  const params = useParams();
  const location = useLocation();
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const { loading, error, responses } = useAppSelector((state) => state.masterApi);
  const {
    requests: exchangeRequests,
    loading: exchangeLoading,
    actionLoading: exchangeActionLoading,
    error: exchangeError,
    successMessage: exchangeSuccess,
  } = useAppSelector((state) => state.exchange);

  const [returnRefundRequests, setReturnRefundRequests] = useState<any[]>([]);
  const [returnRefundLoading, setReturnRefundLoading] = useState(false);
  const [returnRefundSubmitting, setReturnRefundSubmitting] = useState(false);
  const [returnRefundError, setReturnRefundError] = useState<string | null>(null);
  const [returnRefundOpen, setReturnRefundOpen] = useState(false);
  const [exchangeFormOpen, setExchangeFormOpen] = useState(false);
  const [balanceFormOpen, setBalanceFormOpen] = useState(false);
  const [bankFormOpen, setBankFormOpen] = useState(false);
  const [differenceDialogOpen, setDifferenceDialogOpen] = useState(false);
  const [paymentReference, setPaymentReference] = useState("");

  const { resolvedOrderId, resolvedOrderItemId } = useMemo(() => {
    const directOrderId = (params as any).orderId as string | undefined;
    const directOrderItemId = (params as any).orderItemId as string | undefined;
    if (directOrderId) {
      return { resolvedOrderId: directOrderId, resolvedOrderItemId: directOrderItemId };
    }
    const splat = (params as any)["*"] as string | undefined;
    const source = splat && splat.length > 0 ? splat : location.pathname.replace(/^\/account\//, "");
    const parts = source.split("/").filter(Boolean);
    if (parts[0] !== "orders") {
      return { resolvedOrderId: undefined, resolvedOrderItemId: undefined };
    }
    return { resolvedOrderId: parts[1], resolvedOrderItemId: parts[2] };
  }, [location.pathname, params]);

  const successMessageState = (location.state as { successMessage?: string } | null)?.successMessage;
  const initialSuccessMessage =
    typeof successMessageState === "string" ? successMessageState || null : null;

  const [cancelDialogOpen, setCancelDialogOpen] = useState(false);
  const [selectedCancelReason, setSelectedCancelReason] = useState("");
  const [cancelReasonText, setCancelReasonText] = useState("");
  const [cancelSuccess, setCancelSuccess] = useState<string | null>(initialSuccessMessage);

  const order = (responses.orderById || null) as OrderLite | null;
  const selectedItem = (responses.orderItemById || null) as OrderItemLite | null;
  const cancelReasonOptions = useMemo<CancelReasonOption[]>(() => {
    const data: any = responses.orderCancelReasons;
    const reasonsFromData = Array.isArray(data?.reasons) ? data.reasons : [];
    const rawList = Array.isArray(data) ? data : reasonsFromData;
    const parsed = rawList
      .map((reason: any) => {
        if (typeof reason === "string") return { code: reason, label: reason };
        const code = reason?.code || reason?.reasonCode || reason?.value || reason?.id;
        const label = reason?.label || reason?.reason || reason?.title || reason?.name || code;
        if (!code) return null;
        return { code: String(code), label: String(label || code) };
      })
      .filter(Boolean) as CancelReasonOption[];
    if (parsed.length) return parsed;
    return [
      { code: "ORDERED_BY_MISTAKE", label: "Ordered by mistake" },
      { code: "FOUND_BETTER_PRICE", label: "Found better price elsewhere" },
      { code: "DELIVERY_TOO_LATE", label: "Delivery is taking too long" },
      { code: "CHANGED_MY_MIND", label: "Changed my mind" },
      { code: "OTHER", label: "Other" },
    ];
  }, [responses.orderCancelReasons]);

  const item = useMemo(() => {
    if (selectedItem) return selectedItem;
    if (!order) return null;
    if (!resolvedOrderItemId) return (order.orderItems || [])[0] || null;
    return (
      (order.orderItems || []).find(
        (entry) => String(entry.id) === String(resolvedOrderItemId),
      ) ||
      (order.orderItems || [])[0] ||
      null
    );
  }, [selectedItem, order, resolvedOrderItemId]);

  const latestExchangeRequest = useMemo(
    () => selectLatestExchangeForItem(exchangeRequests, item?.id),
    [exchangeRequests, item?.id],
  );

  const {
    handleBalanceMode,
    handleBankDetails,
    handleCancelOrder,
    handleCreateExchange,
    handleDifferencePayment,
    handleSubmitReturnRefund,
    loadReturnRefundRequests,
  } = createOrderDetailsHandlers({
    dispatch,
    item,
    resolvedOrderId,
    selectedCancelReason,
    cancelReasonText,
    latestExchangeRequest,
    paymentReference,
    setReturnRefundRequests,
    setReturnRefundLoading,
    setReturnRefundSubmitting,
    setReturnRefundError,
    setReturnRefundOpen,
    setCancelSuccess,
    setCancelDialogOpen,
    setExchangeFormOpen,
    setDifferenceDialogOpen,
    setPaymentReference,
    setBalanceFormOpen,
    setBankFormOpen,
  });

  const loadReturnRefundRequestsRef = useRef(loadReturnRefundRequests);
  loadReturnRefundRequestsRef.current = loadReturnRefundRequests;

  useEffect(() => {
    if (!resolvedOrderId) return;

    const loadOrder = () => {
      dispatch(orderById(resolvedOrderId));
      dispatch(userOrderHistory());
      dispatch(fetchExchangeRequests());
      loadReturnRefundRequestsRef.current();
      if (resolvedOrderItemId) dispatch(orderItemById(resolvedOrderItemId));
    };

    loadOrder();
    dispatch(orderCancelReasons());

    const intervalId = globalThis.setInterval(loadOrder, 20000);
    const handleFocus = () => loadOrder();
    globalThis.addEventListener("focus", handleFocus);
    document.addEventListener("visibilitychange", handleFocus);

    return () => {
      globalThis.clearInterval(intervalId);
      globalThis.removeEventListener("focus", handleFocus);
      document.removeEventListener("visibilitychange", handleFocus);
    };
  }, [dispatch, resolvedOrderId, resolvedOrderItemId]);

  useEffect(() => () => {
    dispatch(clearExchangeError());
    dispatch(clearExchangeSuccess());
  }, [dispatch]);

  const latestReturnRefundRequest = useMemo(() => (
    returnRefundRequests
      .filter((entry) => String(entry.orderItemId) === String(item?.id || ""))
      .sort((left, right) => new Date(right.requestedAt || 0).getTime() - new Date(left.requestedAt || 0).getTime())[0] || null
  ), [item?.id, returnRefundRequests]);

  const hasActiveReturnRefundRequest = latestReturnRefundRequest
    ? !["REFUND_COMPLETED", "RETURN_REJECTED"].includes((latestReturnRefundRequest.status || "").toUpperCase())
    : false;

  const rawOrderStatus = (order?.orderStatus || "PENDING").toUpperCase();
  const shipmentStatus = (order?.shipmentStatus || rawOrderStatus).toUpperCase();
  const deliveryTaskStatus = (order?.deliveryTaskStatus || "").toUpperCase();
  const pendingReason = order?.deliveryStatusReason || "";
  const sanitizedPendingReason = /verified|delivered/i.test(pendingReason) ? "" : pendingReason;
  const customerStatus = resolveCustomerStatus(order);
  const canCancel = cancelAllowed.has(rawOrderStatus);
  const courierName = order?.courier?.fullName || order?.courier?.name || order?.courierName;
  const courierPhone = order?.courier?.phone || order?.courierPhone;
  const trackingSteps = buildTrackingMilestones({
    orderStatus: rawOrderStatus,
    fulfillmentStatus: order?.fulfillmentStatus,
    shipmentStatus,
  });
  const showCourierCard = ["OUT_FOR_DELIVERY", "DELIVERED", "ARRIVED", "CONFIRMATION_PENDING"].includes(shipmentStatus) || deliveryTaskStatus === "CONFIRMATION_PENDING";
  const deliveryDateMs = order?.deliveryDate ? new Date(order.deliveryDate).getTime() : 0;
  const deliveredWithin48Hours = customerStatus === "DELIVERED" && deliveryDateMs > 0 && Date.now() - deliveryDateMs <= 48 * 60 * 60 * 1000;
  const canRequestReturnRefund = deliveredWithin48Hours && !!item?.id && !hasActiveReturnRefundRequest;
  const canRequestExchange = deliveredWithin48Hours && !!item?.id && !hasActiveExchange(latestExchangeRequest);
  const productOptions = useMemo(() => {
    const options = new Map<string, { id: number | string; title: string }>();
    if (item?.product?.id) {
      options.set(String(item.product.id), { id: item.product.id, title: item.product.title || "Current Product" });
    }
    (order?.orderItems || []).forEach((entry) => {
      if (entry.product?.id) {
        options.set(String(entry.product.id), { id: entry.product.id, title: entry.product.title || `Product ${entry.product.id}` });
      }
    });
    return Array.from(options.values());
  }, [item?.product?.id, item?.product?.title, order?.orderItems]);
  const exchangeProductOptions = productOptions.length
    ? productOptions
    : [
        {
          id: item?.product?.id || 0,
          title: item?.product?.title || "Current Product",
        },
      ];

  if (loading && !order) {
    return (
      <div className="py-20 flex justify-center">
        <CircularProgress thickness={2} />
      </div>
    );
  }

  if (error && !order) return <Alert severity="error" className="rounded-xl">{error}</Alert>;
  if (!order) return <Alert severity="warning" className="rounded-xl">Order not found.</Alert>;

  return (
    <div className="max-w-5xl mx-auto space-y-8 pb-20">
      <OrderDetailsHeaderSection
        customerStatus={customerStatus}
        paymentStatus={order.paymentStatus}
        latestExchangeStatus={latestExchangeRequest?.status}
        cancelSuccess={cancelSuccess}
        exchangeSuccess={exchangeSuccess}
        exchangeError={exchangeError}
        onCloseExchangeSuccess={() => dispatch(clearExchangeSuccess())}
        onCloseExchangeError={() => dispatch(clearExchangeError())}
        order={order}
        trackingCompleted={trackingSteps.filter((step) => step.completed).length}
        trackingTotal={trackingSteps.length}
        returnRefundLoading={returnRefundLoading}
        exchangeLoading={exchangeLoading}
      />

      <OrderDetailsJourneySection
        rawOrderStatus={rawOrderStatus}
        shipmentStatus={shipmentStatus}
        order={order}
        trackingSteps={trackingSteps}
        latestReturnRefundRequest={latestReturnRefundRequest}
        returnRefundError={returnRefundError}
        returnRefundOpen={returnRefundOpen}
        latestExchangeRequest={latestExchangeRequest}
        onPayDifference={() => setDifferenceDialogOpen(true)}
        onSelectBalanceMode={() => setBalanceFormOpen(true)}
        onSubmitBankDetails={() => setBankFormOpen(true)}
        deliveryTaskStatus={deliveryTaskStatus}
        sanitizedPendingReason={sanitizedPendingReason}
        showCourierCard={showCourierCard}
        courierName={courierName}
        courierPhone={courierPhone}
      />

      <OrderDetailsProductInfo
        orderId={order.id}
        customerStatus={customerStatus}
        item={item}
      />

      <Stack direction={{ xs: "column", md: "row" }} spacing={2}>
        {canRequestReturnRefund && (
          <Button fullWidth variant="contained" onClick={() => setReturnRefundOpen(true)} sx={{ borderRadius: "12px", py: 1.5, fontWeight: 800, boxShadow: "none", bgcolor: "#111827", "&:hover": { bgcolor: "#000000" } }}>
            Return & Refund
          </Button>
        )}
        {canRequestExchange && (
          <Button fullWidth variant="outlined" onClick={() => setExchangeFormOpen(true)} sx={{ borderRadius: "12px", py: 1.5, fontWeight: 800, borderColor: "#d1d5db", color: "#111827", "&:hover": { borderColor: "#111827", bgcolor: "#f9fafb" } }}>
            Exchange
          </Button>
        )}
      </Stack>

      {latestReturnRefundRequest && !canRequestReturnRefund && hasActiveReturnRefundRequest && (
        <Alert severity="info">Return & Refund request is currently in progress for this item.</Alert>
      )}
      {latestExchangeRequest && hasActiveExchange(latestExchangeRequest) && (
        <Alert severity="info">Exchange request is currently in progress for this item.</Alert>
      )}
      {customerStatus === "DELIVERED" && !deliveredWithin48Hours && (
        <Alert severity="warning">Return & Refund and Exchange are available only within 48 hours after delivery.</Alert>
      )}

      <div className="flex flex-col sm:flex-row gap-4 pt-2">
        <Button fullWidth variant="outlined" onClick={() => navigate("/account/orders")} sx={{ borderRadius: "12px", py: 1.5, color: "black", borderColor: "#e5e7eb", "&:hover": { borderColor: "black" }, fontWeight: "bold" }}>
          Back to Orders
        </Button>
        {canCancel && (
          <Button fullWidth variant="contained" color="error" disabled={loading} onClick={() => setCancelDialogOpen(true)} sx={{ borderRadius: "12px", py: 1.5, fontWeight: "black", boxShadow: "none" }}>
            Cancel Order
          </Button>
        )}
      </div>

      <OrderDetailsDialogs
        cancelDialogOpen={cancelDialogOpen}
        selectedCancelReason={selectedCancelReason}
        cancelReasonText={cancelReasonText}
        cancelReasonOptions={cancelReasonOptions}
        loading={loading}
        onCloseCancel={() => setCancelDialogOpen(false)}
        onCancelReasonChange={setSelectedCancelReason}
        onCancelReasonTextChange={setCancelReasonText}
        onConfirmCancel={handleCancelOrder}
        differenceDialogOpen={differenceDialogOpen}
        exchangeActionLoading={exchangeActionLoading}
        paymentReference={paymentReference}
        onCloseDifference={() => setDifferenceDialogOpen(false)}
        onPaymentReferenceChange={setPaymentReference}
        onSubmitDifference={handleDifferencePayment}
      />

      <ReturnRefundForm open={returnRefundOpen} loading={returnRefundSubmitting} error={returnRefundError} orderItemTitle={item?.product?.title} onClose={() => setReturnRefundOpen(false)} onSubmit={handleSubmitReturnRefund} />
      <ExchangeRequestForm open={exchangeFormOpen} loading={exchangeActionLoading} error={exchangeError} orderItemTitle={item?.product?.title} productOptions={exchangeProductOptions} onClose={() => setExchangeFormOpen(false)} onSubmit={handleCreateExchange} />
      <BalanceSelectionForm open={balanceFormOpen} loading={exchangeActionLoading} onClose={() => setBalanceFormOpen(false)} onSubmit={handleBalanceMode} />
      <BankDetailsForm open={bankFormOpen} loading={exchangeActionLoading} initial={latestExchangeRequest?.bankDetails || latestExchangeRequest?.balanceHandling?.bankDetails || null} onClose={() => setBankFormOpen(false)} onSubmit={handleBankDetails} />
    </div>
  );
};

export default OrderDetails;

import React, { useEffect, useMemo, useState } from "react";
import { Alert, CircularProgress } from "@mui/material";
import TuneOutlinedIcon from "@mui/icons-material/TuneOutlined";
import { useNavigate } from "react-router-dom";
import { userOrderHistory } from "State/backend/MasterApiThunks";
import { useAppDispatch, useAppSelector } from "app/store/Store";
import OrderItem from "./OrderItem";

type ProductLite = {
  id: number;
  title?: string;
  description?: string;
  images?: string[];
};

type OrderItemLite = {
  id?: number;
  product?: ProductLite;
  size?: string;
};

type OrderLite = {
  id: number;
  orderStatus?: string;
  paymentStatus?: string;
  fulfillmentStatus?: string;
  shipmentStatus?: string;
  deliveryTaskStatus?: string;
  deliveryStatusReason?: string;
  orderDate?: string;
  cancelledAt?: string;
  cancelReasonText?: string;
  deliveryWindow?: string;
  orderItems?: OrderItemLite[];
};

const deriveDisplayStatus = (order: OrderLite) => {
  const shipmentStatus = (order.shipmentStatus || "").toUpperCase();
  const deliveryTaskStatus = (order.deliveryTaskStatus || "").toUpperCase();
  const orderStatus = (order.orderStatus || "PENDING").toUpperCase();
  const fulfillmentStatus = (order.fulfillmentStatus || "").toUpperCase();

  if (orderStatus === "CANCELLED") return "CANCELLED";
  if (shipmentStatus === "DELIVERED" || orderStatus === "DELIVERED") return "DELIVERED";
  if (deliveryTaskStatus === "CONFIRMATION_PENDING") return "CONFIRMATION_PENDING";
  if (deliveryTaskStatus === "ARRIVED") return "ARRIVED_AT_LOCATION";
  if (shipmentStatus === "OUT_FOR_DELIVERY" || deliveryTaskStatus === "OUT_FOR_DELIVERY") return "OUT_FOR_DELIVERY";
  if (["IN_TRANSIT", "HANDED_TO_COURIER"].includes(shipmentStatus)) return "SHIPPED";
  if (fulfillmentStatus === "FULFILLED") return "PACKED";
  if (orderStatus === "CONFIRMED") return "CONFIRMED";
  return orderStatus;
};

const isInProgressStatus = (status: string) => !["DELIVERED", "CANCELLED"].includes(status);

const Orders = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const { loading, error, responses } = useAppSelector((state) => state.masterApi);
  const [query, setQuery] = useState("");
  const [statusFilter, setStatusFilter] = useState<"ALL" | "DELIVERED" | "CANCELLED" | "IN_PROGRESS">("ALL");

  const orders = useMemo(
    () => (responses.userOrderHistory || []) as OrderLite[],
    [responses.userOrderHistory],
  );

  useEffect(() => {
    dispatch(userOrderHistory());
    const intervalId = globalThis.setInterval(() => {
      dispatch(userOrderHistory());
    }, 30000);
    const handleFocus = () => dispatch(userOrderHistory());
    globalThis.addEventListener("focus", handleFocus);
    document.addEventListener("visibilitychange", handleFocus);
    return () => {
      globalThis.clearInterval(intervalId);
      globalThis.removeEventListener("focus", handleFocus);
      document.removeEventListener("visibilitychange", handleFocus);
    };
  }, [dispatch]);

  const handleOpenOrder = (orderId: number, orderItemId?: number) => {
    if (orderItemId) {
      navigate(`/account/orders/${orderId}/${orderItemId}`);
      return;
    }
    navigate(`/account/orders/${orderId}`);
  };

  const formatStatusDate = (order: OrderLite) => {
    const raw = (order.orderStatus || "").toUpperCase() === "CANCELLED"
      ? order.cancelledAt || order.orderDate
      : order.orderDate;
    if (!raw) return "";
    const date = new Date(raw);
    if (Number.isNaN(date.getTime())) return "";
    return date.toLocaleDateString(undefined, {
      weekday: "short",
      day: "numeric",
      month: "short",
      year: "numeric",
    });
  };

  const filteredOrders = useMemo(() => {
    return orders
      .map((order) => {
        const displayStatus = deriveDisplayStatus(order);
        return {
          ...order,
          displayStatus,
          orderItems: (order.orderItems || []).filter((item) => {
            const title = (item.product?.title || "").toLowerCase();
            const desc = (item.product?.description || "").toLowerCase();
            const textMatch =
              query.trim() === "" ||
              title.includes(query.toLowerCase()) ||
              desc.includes(query.toLowerCase());

            const statusMatch =
              statusFilter === "ALL" ||
              (statusFilter === "IN_PROGRESS" && isInProgressStatus(displayStatus)) ||
              displayStatus === statusFilter;

            return textMatch && statusMatch;
          }),
        };
      })
      .filter((order) => (order.orderItems || []).length > 0);
  }, [orders, query, statusFilter]);

  return (
    <div className="w-full space-y-4">
      <div>
        <h1 className="text-xl font-bold">Orders</h1>
        <p className="text-sm text-gray-500">Live tracking updates now follow shipment and courier task milestones.</p>
      </div>

      <div className="flex gap-2 mb-4">
        <input
          className="flex-1 border border-gray-300 rounded px-3 py-2 text-sm outline-none focus:border-gray-500"
          placeholder="Search in orders"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
        />
        <div className="relative">
          <TuneOutlinedIcon className="absolute left-2 top-2.5 text-gray-500" sx={{ fontSize: 18 }} />
          <select
            className="border border-gray-300 rounded pl-7 pr-2 py-2 text-sm bg-white"
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value as any)}
          >
            <option value="ALL">Filter</option>
            <option value="IN_PROGRESS">In Progress</option>
            <option value="DELIVERED">Delivered</option>
            <option value="CANCELLED">Cancelled</option>
          </select>
        </div>
      </div>

      {loading && orders.length === 0 && (
        <div className="py-10 flex justify-center">
          <CircularProgress />
        </div>
      )}

      {error && <Alert severity="error">{error}</Alert>}

      {!loading && !error && filteredOrders.length === 0 && (
        <p className="text-gray-500">No orders found yet.</p>
      )}

      <div className="space-y-4">
        {filteredOrders.flatMap((order) =>
          (order.orderItems || []).map((item) => (
            <OrderItem
              key={item.id || `${order.id}-${item.product?.id || "product"}`}
              id={item.id}
              orderId={order.id}
              title={item.product?.title || "Product"}
              description={item.product?.description}
              size={item.size}
              image={item.product?.images?.[0]}
              orderStatus={order.displayStatus}
              statusDate={formatStatusDate(order)}
              cancelReasonText={order.cancelReasonText || order.deliveryStatusReason}
              onOpen={handleOpenOrder}
            />
          )),
        )}
      </div>
    </div>
  );
};

export default Orders;

import React, { useState } from "react";
import { Button, Dialog, DialogActions, DialogContent, DialogTitle, FormControl, InputLabel, MenuItem, Select, Stack, Typography } from "@mui/material";

type Props = {
  open: boolean;
  loading?: boolean;
  onClose: () => void;
  onSubmit: (balanceMode: "WALLET" | "BANK_TRANSFER") => Promise<void> | void;
};

const BalanceSelectionForm = ({ open, loading = false, onClose, onSubmit }: Props) => {
  const [balanceMode, setBalanceMode] = useState<"WALLET" | "BANK_TRANSFER">("WALLET");
  return (
    <Dialog open={open} onClose={loading ? undefined : onClose} fullWidth maxWidth="xs">
      <DialogTitle>Select Balance Handling</DialogTitle>
      <DialogContent>
        <Stack spacing={2.5} sx={{ pt: 1 }}>
          <Typography variant="body2" color="text.secondary">Choose how the remaining balance should be handled when the new product price is lower than the old product price.</Typography>
          <FormControl fullWidth>
            <InputLabel id="balance-mode">Balance mode</InputLabel>
            <Select labelId="balance-mode" value={balanceMode} label="Balance mode" onChange={(e) => setBalanceMode(e.target.value as any)}>
              <MenuItem value="WALLET">Store in Wallet</MenuItem>
              <MenuItem value="BANK_TRANSFER">Transfer to Bank</MenuItem>
            </Select>
          </FormControl>
        </Stack>
      </DialogContent>
      <DialogActions sx={{ p: 3 }}>
        <Button onClick={onClose} disabled={loading}>Cancel</Button>
        <Button variant="contained" onClick={() => onSubmit(balanceMode)} disabled={loading}>Continue</Button>
      </DialogActions>
    </Dialog>
  );
};

export default BalanceSelectionForm;

