import React, { ChangeEvent, useEffect, useState } from "react";
import {
  Alert,
  Box,
  Button,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  Stack,
  TextField,
  Typography,
} from "@mui/material";

type ReturnRefundFormProps = {
  open: boolean;
  loading?: boolean;
  error?: string | null;
  orderItemTitle?: string;
  onClose: () => void;
  onSubmit: (payload: {
    returnReason: string;
    comment?: string;
    productPhoto?: string;
    accountHolderName?: string;
    accountNumber?: string;
    ifscCode?: string;
    bankName?: string;
    upiId?: string;
  }) => Promise<void> | void;
};

const ReturnRefundForm = ({ open, loading = false, error, orderItemTitle, onClose, onSubmit }: ReturnRefundFormProps) => {
  const [returnReason, setReturnReason] = useState("");
  const [comment, setComment] = useState("");
  const [productPhotoName, setProductPhotoName] = useState("");
  const [accountHolderName, setAccountHolderName] = useState("");
  const [accountNumber, setAccountNumber] = useState("");
  const [ifscCode, setIfscCode] = useState("");
  const [bankName, setBankName] = useState("");
  const [upiId, setUpiId] = useState("");

  useEffect(() => {
    if (!open) return;
    setReturnReason("");
    setComment("");
    setProductPhotoName("");
    setAccountHolderName("");
    setAccountNumber("");
    setIfscCode("");
    setBankName("");
    setUpiId("");
  }, [open]);

  const handlePhotoChange = (event: ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0] || null;
    setProductPhotoName(file?.name || "");
  };

  return (
    <Dialog open={open} onClose={loading ? undefined : onClose} fullWidth maxWidth="sm" PaperProps={{ sx: { borderRadius: "20px", p: 1 } }}>
      <DialogTitle sx={{ fontWeight: 900, fontSize: 26 }}>Return & Refund</DialogTitle>
