import { api } from "shared/api/Api";
import { createOrderDetailsHandlers } from "./orderDetailsHandlers";

const createStateSetters = () => ({
  setReturnRefundRequests: jest.fn(),
  setReturnRefundLoading: jest.fn(),
  setReturnRefundSubmitting: jest.fn(),
  setReturnRefundError: jest.fn(),
  setReturnRefundOpen: jest.fn(),
  setCancelSuccess: jest.fn(),
  setCancelDialogOpen: jest.fn(),
  setExchangeFormOpen: jest.fn(),
  setDifferenceDialogOpen: jest.fn(),
  setPaymentReference: jest.fn(),
  setBalanceFormOpen: jest.fn(),
  setBankFormOpen: jest.fn(),
});

describe("orderDetailsHandlers", () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  test("loads return/refund requests and normalizes array data", async () => {
    const getSpy = jest.spyOn(api, "get").mockResolvedValue({
      data: [{ id: 1, orderItemId: 11 }],
    } as any);
    const setters = createStateSetters();
    const dispatchMock = jest.fn(() => ({
      unwrap: jest.fn().mockResolvedValue({}),
    }));

    const handlers = createOrderDetailsHandlers({
      dispatch: dispatchMock as any,
      item: { id: 11 } as any,
      resolvedOrderId: "101",
      selectedCancelReason: "OTHER",
      cancelReasonText: "test",
      latestExchangeRequest: { id: 500 },
      paymentReference: "PAY-1",
      ...setters,
    });

    await handlers.loadReturnRefundRequests();

    expect(getSpy).toHaveBeenCalledWith("/api/orders/returns");
    expect(setters.setReturnRefundRequests).toHaveBeenCalledWith([
      { id: 1, orderItemId: 11 },
    ]);
    expect(setters.setReturnRefundLoading).toHaveBeenCalledWith(true);
    expect(setters.setReturnRefundLoading).toHaveBeenLastCalledWith(false);
  });

  test("does not dispatch cancel when reason is missing", async () => {
    const setters = createStateSetters();
    const dispatchMock = jest.fn(() => ({
      unwrap: jest.fn().mockResolvedValue({}),
    }));
    const handlers = createOrderDetailsHandlers({
      dispatch: dispatchMock as any,
      item: { id: 11 } as any,
      resolvedOrderId: "101",
      selectedCancelReason: "",
      cancelReasonText: "",
      latestExchangeRequest: { id: 500 },
      paymentReference: "PAY-1",
      ...setters,
    });

    await handlers.handleCancelOrder();

    expect(dispatchMock).not.toHaveBeenCalled();
  });

  test("submits difference payment and resets dialog state", async () => {
    const setters = createStateSetters();
    const dispatchMock = jest.fn(() => ({
      unwrap: jest.fn().mockResolvedValue({}),
    }));
    const handlers = createOrderDetailsHandlers({
      dispatch: dispatchMock as any,
      item: { id: 11 } as any,
      resolvedOrderId: "101",
      selectedCancelReason: "OTHER",
      cancelReasonText: "test",
      latestExchangeRequest: { id: 500 },
      paymentReference: "REF-123",
      ...setters,
    });

    await handlers.handleDifferencePayment();

    expect(dispatchMock).toHaveBeenCalled();
    expect(setters.setDifferenceDialogOpen).toHaveBeenCalledWith(false);
    expect(setters.setPaymentReference).toHaveBeenCalledWith("");
  });
});

import React from "react";
import { api } from "shared/api/Api";
import { AppDispatch } from "app/store/Store";
import {
  cancelOrder,
  orderById,
  userOrderHistory,
} from "State/backend/MasterApiThunks";
import {
  createExchangeRequest,
  fetchExchangeRequests,
  selectExchangeBalanceMode,
  submitDifferencePayment,
  submitExchangeBankDetails,
} from "State/features/customer/exchange/slice";
import { OrderItemLite } from "./orderDetailsTypes";

type ReturnRefundPayload = {
  returnReason: string;
  comment?: string;
  productPhoto?: string;
  accountHolderName?: string;
  accountNumber?: string;
  ifscCode?: string;
  bankName?: string;
  upiId?: string;
};

type ExchangePayload = {
  exchangeReason: string;
  comment?: string;
  productPhoto?: string;
  requestedVariant?: string;
  requestedNewProductId: number | string;
};

type BankDetailsPayload = {
  accountHolderName?: string;
  accountNumber?: string;
  ifscCode?: string;
  bankName?: string;
  upiId?: string;
};

type CreateOrderDetailsHandlersParams = {
  dispatch: AppDispatch;
  item: OrderItemLite | null;
  resolvedOrderId?: string;
  selectedCancelReason: string;
  cancelReasonText: string;
  latestExchangeRequest: any;
  paymentReference: string;
  setReturnRefundRequests: React.Dispatch<React.SetStateAction<any[]>>;
  setReturnRefundLoading: React.Dispatch<React.SetStateAction<boolean>>;
  setReturnRefundSubmitting: React.Dispatch<React.SetStateAction<boolean>>;
  setReturnRefundError: React.Dispatch<React.SetStateAction<string | null>>;
  setReturnRefundOpen: React.Dispatch<React.SetStateAction<boolean>>;
  setCancelSuccess: React.Dispatch<React.SetStateAction<string | null>>;
  setCancelDialogOpen: React.Dispatch<React.SetStateAction<boolean>>;
  setExchangeFormOpen: React.Dispatch<React.SetStateAction<boolean>>;
  setDifferenceDialogOpen: React.Dispatch<React.SetStateAction<boolean>>;
  setPaymentReference: React.Dispatch<React.SetStateAction<string>>;
  setBalanceFormOpen: React.Dispatch<React.SetStateAction<boolean>>;
  setBankFormOpen: React.Dispatch<React.SetStateAction<boolean>>;
};

export const createOrderDetailsHandlers = ({
  dispatch,
  item,
  resolvedOrderId,
  selectedCancelReason,
  cancelReasonText,
  latestExchangeRequest,
  paymentReference,
  setReturnRefundRequests,
  setReturnRefundLoading,
  setReturnRefundSubmitting,
  setReturnRefundError,
  setReturnRefundOpen,
  setCancelSuccess,
  setCancelDialogOpen,
  setExchangeFormOpen,
  setDifferenceDialogOpen,
  setPaymentReference,
  setBalanceFormOpen,
  setBankFormOpen,
}: CreateOrderDetailsHandlersParams) => {
  const loadReturnRefundRequests = async () => {
    setReturnRefundLoading(true);
    setReturnRefundError(null);
    try {
      const response = await api.get("/api/orders/returns");
      setReturnRefundRequests(Array.isArray(response.data) ? response.data : []);
    } catch (requestError: any) {
      setReturnRefundError(
        requestError?.response?.data?.message ||
          "Failed to load return refund requests",
      );
    } finally {
      setReturnRefundLoading(false);
    }
  };

  const handleSubmitReturnRefund = async (payload: ReturnRefundPayload) => {
    if (!item?.id) return;
    setReturnRefundSubmitting(true);
    setReturnRefundError(null);
    try {
      await api.post("/api/orders/returns/items/" + item.id, {
        returnReason: payload.returnReason,
        comment: payload.comment,
        productPhoto: payload.productPhoto,
        refundDetails: {
          accountHolderName: payload.accountHolderName,
          accountNumber: payload.accountNumber,
          ifscCode: payload.ifscCode,
          bankName: payload.bankName,
          upiId: payload.upiId,
        },
      });
      setReturnRefundOpen(false);
      await loadReturnRefundRequests();
    } catch (requestError: any) {
      setReturnRefundError(
        requestError?.response?.data?.message || "Failed to submit return request",
      );
    } finally {
      setReturnRefundSubmitting(false);
    }
  };

  const handleCancelOrder = async () => {
    if (!resolvedOrderId || !selectedCancelReason) return;
    try {
      await dispatch(
        cancelOrder({
          orderId: resolvedOrderId,
          cancelReasonCode: selectedCancelReason,
          cancelReasonText: cancelReasonText.trim() || undefined,
        }),
      ).unwrap();
      setCancelSuccess("Order cancelled successfully.");
      setCancelDialogOpen(false);
      dispatch(orderById(resolvedOrderId));
      dispatch(userOrderHistory());
    } catch (cancelError) {
      console.error("Cancellation failed", cancelError);
    }
  };

  const handleCreateExchange = async (payload: ExchangePayload) => {
    if (!item?.id) return;
    await dispatch(createExchangeRequest({ orderItemId: item.id, ...payload })).unwrap();
    setExchangeFormOpen(false);
    dispatch(fetchExchangeRequests());
  };

  const handleDifferencePayment = async () => {
    if (!latestExchangeRequest?.id || !paymentReference.trim()) return;
    await dispatch(
      submitDifferencePayment({
        requestId: latestExchangeRequest.id,
        paymentReference: paymentReference.trim(),
      }),
    ).unwrap();
    setDifferenceDialogOpen(false);
    setPaymentReference("");
    dispatch(fetchExchangeRequests());
  };

  const handleBalanceMode = async (balanceMode: "WALLET" | "BANK_TRANSFER") => {
    if (!latestExchangeRequest?.id) return;
    await dispatch(
      selectExchangeBalanceMode({
        requestId: latestExchangeRequest.id,
        balanceMode,
      }),
    ).unwrap();
    setBalanceFormOpen(false);
    dispatch(fetchExchangeRequests());
  };

  const handleBankDetails = async (payload: BankDetailsPayload) => {
    if (
      !latestExchangeRequest?.id ||
      !payload.accountHolderName ||
      !payload.accountNumber ||
      !payload.ifscCode ||
      !payload.bankName
    ) {
      return;
    }
    await dispatch(
      submitExchangeBankDetails({
        requestId: latestExchangeRequest.id,
        accountHolderName: payload.accountHolderName,
        accountNumber: payload.accountNumber,
        ifscCode: payload.ifscCode,
        bankName: payload.bankName,
        upiId: payload.upiId,
      }),
    ).unwrap();
    setBankFormOpen(false);
    dispatch(fetchExchangeRequests());
  };

  return {
    handleBalanceMode,
    handleBankDetails,
    handleCancelOrder,
    handleCreateExchange,
    handleDifferencePayment,
    handleSubmitReturnRefund,
    loadReturnRefundRequests,
  };
};

import React from "react";
import {
  TextField,
  Button,
  Box,
  Typography,
  Alert,
  CircularProgress,
} from "@mui/material";
import { useFormik } from "formik";
import * as Yup from "yup";
import { useAppDispatch, useAppSelector } from "app/store/Store";
import { register, sendOtp } from "State/features/customer/auth/thunks";

interface Props {
  onSuccess: () => void;
}

const RegisterFrom = ({ onSuccess }: Props) => {
  const dispatch = useAppDispatch();
  const { otpSent, loading, error } = useAppSelector(
    (state: any) => state.customerAuth
  );

  const formik = useFormik({
    initialValues: { fullName: "", email: "", otp: "" },
    validationSchema: Yup.object({
      fullName: Yup.string().required("Required"),
      email: Yup.string().email("Invalid email").required("Required"),
      otp: otpSent
        ? Yup.string().length(6).required("Required")
        : Yup.string(),
    }),
    onSubmit: async (values) => {
      if (!otpSent) {
        dispatch(sendOtp({ email: values.email, isLogin: false }));
      } else {
        const result = await dispatch(register(values));

        // ✅ If register success → switch to login
        if (register.fulfilled.match(result)) {
          formik.resetForm();
          onSuccess();
        }
      }
    },
  });

  return (
    <Box component="form" onSubmit={formik.handleSubmit}>
      <Typography variant="h5" mb={2}>
        Create Account
      </Typography>

      {error && <Alert severity="error">{error}</Alert>}

      <TextField
        fullWidth
        label="Full Name"
        margin="normal"
        disabled={otpSent}
        {...formik.getFieldProps("fullName")}
      />

      <TextField
        fullWidth
        label="Email"
        margin="normal"
        disabled={otpSent}
        {...formik.getFieldProps("email")}
      />

      {otpSent && (
        <TextField
          fullWidth
          label="OTP"
          margin="normal"
          {...formik.getFieldProps("otp")}
        />
      )}

      <Button
        fullWidth
        type="submit"
        variant="contained"
        sx={{ mt: 2 }}
        disabled={loading}
      >
        {loading ? (
          <CircularProgress size={24} />
        ) : otpSent ? (
          "Register"
        ) : (
          "Send OTP"
        )}
      </Button>
    </Box>
  );
};

export default RegisterFrom;

